import json
from pathlib import Path

DATA_FILE = Path('vokabeln.json')

def load_vocab():
    if not DATA_FILE.exists():
        return []
    with DATA_FILE.open('r', encoding='utf-8') as f:
        return json.load(f)

def save_vocab(items):
    with DATA_FILE.open('w', encoding='utf-8') as f:
        json.dump(items, f, ensure_ascii=False, indent=2)

Quiz-Loop implementiert:

import random

def run_quiz(vocab):
    score = 0
    random.shuffle(vocab)
    for entry in vocab:
        ans = input(f"Uebersetze '{entry['de']}': ").strip().lower()
        if ans == entry['en'].strip().lower():
            score += 1
            print('Richtig!')
        else:
            print(f"Falsch. Richtig waere: {entry['en']}")
    return score, len(vocab)

